// Generated by AI (UnitTest MCP)
import { EventEmitter } from "events";
import { PassThrough } from "stream";

import { spawn } from "child_process";
import { beforeEach, describe, expect, it, vi } from "vitest";

import { McpClient } from "./mcpClient";

vi.mock("child_process", () => ({ spawn: vi.fn() }));

const mockedSpawn = vi.mocked(spawn);

beforeEach(() => {
  mockedSpawn.mockReset();
});

describe("McpClient disposal", () => {
  it("closes stdin and waits for a graceful server exit", async () => {
    const fake = fakeProcess({ exitOnEnd: true });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();

    await client.dispose(100);

    expect(fake.end).toHaveBeenCalledOnce();
    expect(fake.kill).not.toHaveBeenCalled();
    expect(client.isReady()).toBe(false);
  });

  it("force-kills after the grace period when EOF does not stop the server", async () => {
    const fake = fakeProcess({ exitOnEnd: false });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();

    await client.dispose(1);

    expect(fake.end).toHaveBeenCalledOnce();
    expect(fake.kill).toHaveBeenCalledOnce();
  });

  it("rejects pending requests when disposed", async () => {
    const fake = fakeProcess({ exitOnEnd: true });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();
    const pending = client.callTool("graph_stats", {});

    await client.dispose(100);

    await expect(pending).rejects.toThrow("disposed");
  });

  it("parses successful tool content and surfaces tool errors", async () => {
    const fake = fakeProcess({
      exitOnEnd: true,
      toolResults: [
        { content: [{ type: "text", text: '{"nodes":2}' }] },
        { isError: true, content: [{ type: "text", text: "tool failed" }] },
      ],
    });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();

    await expect(client.callTool("graph_stats", {})).resolves.toEqual({ nodes: 2 });
    await expect(client.callTool("graph_stats", {})).rejects.toThrow("tool failed");
    await client.dispose(100);
  });

  it("logs malformed server output without failing later responses", async () => {
    const logs: string[] = [];
    const fake = fakeProcess({ exitOnEnd: true });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, (message) => logs.push(message));
    await client.start();

    fake.process.stdout.write("not-json\n");
    await vi.waitFor(() =>
      expect(logs.some((message) => message.includes("unparseable"))).toBe(true)
    );
    await client.dispose(100);
  });

  it("ignores blank, notification, and unmatched response lines and logs spawn errors", async () => {
    const logs: string[] = [];
    const fake = fakeProcess({ exitOnEnd: true });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, (message) => logs.push(message));
    await client.start();

    fake.process.stdout.write("\n");
    fake.process.stdout.write('{"jsonrpc":"2.0","method":"notice"}\n');
    fake.process.stdout.write('{"jsonrpc":"2.0","id":999,"result":{}}\n');
    fake.process.emit("error", new Error("spawn failed"));
    await vi.waitFor(() =>
      expect(logs.some((message) => message.includes("spawn failed"))).toBe(true)
    );
    await client.dispose(100);
  });

  it("surfaces JSON-RPC errors and fallback tool errors", async () => {
    const fake = fakeProcess({
      exitOnEnd: true,
      toolMessages: [{ error: { message: "rpc failed" } }, { result: { isError: true } }],
    });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();

    await expect(client.callTool("graph_stats", {})).rejects.toThrow("rpc failed");
    await expect(client.callTool("graph_stats", {})).rejects.toThrow("tool error");
    await client.dispose(100);
  });

  it("rejects calls before start and allows repeated disposal", async () => {
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await expect(client.callTool("graph_stats", {})).rejects.toThrow("not started");
    await client.dispose();
    await client.dispose();
  });

  it("returns immediately when the process already exited", async () => {
    const fake = fakeProcess({ exitOnEnd: false });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();
    fake.exit(0);

    await client.dispose(100);

    expect(fake.end).not.toHaveBeenCalled();
  });

  it("finishes disposal when force-kill reports no process", async () => {
    const fake = fakeProcess({ exitOnEnd: false, killResult: false });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();

    await client.dispose(1);

    expect(fake.kill).toHaveBeenCalledOnce();
  });

  it("escalates and finishes when SIGTERM is accepted without exit", async () => {
    const fake = fakeProcess({ exitOnEnd: false, emitExitOnKill: false });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();

    await client.dispose(1, 1);

    expect(fake.kill).toHaveBeenNthCalledWith(1);
    expect(fake.kill).toHaveBeenNthCalledWith(2, "SIGKILL");
  });

  it("rejects pending work when the server exits without a code", async () => {
    const fake = fakeProcess({ exitOnEnd: false });
    mockedSpawn.mockReturnValue(fake.process);
    const client = new McpClient("mindleak-mcp", "/workspace", {}, () => undefined);
    await client.start();
    const pending = client.callTool("graph_stats", {});
    fake.exit(null);

    await expect(pending).rejects.toThrow("code null");
  });
});

function fakeProcess(options: {
  exitOnEnd: boolean;
  emitExitOnKill?: boolean;
  killResult?: boolean;
  toolResults?: unknown[];
  toolMessages?: Array<{ result?: unknown; error?: unknown }>;
}) {
  const process = new EventEmitter() as any;
  process.stdout = new PassThrough();
  process.stderr = new PassThrough();
  process.stdin = new PassThrough();
  process.exitCode = null;
  const exit = (code: number | null) => {
    process.exitCode = code;
    process.emit("exit", code);
  };
  let buffered = "";
  process.stdin.on("data", (chunk: Buffer) => {
    buffered += chunk.toString();
    for (;;) {
      const newline = buffered.indexOf("\n");
      if (newline < 0) {
        break;
      }
      const line = buffered.slice(0, newline);
      buffered = buffered.slice(newline + 1);
      const request = JSON.parse(line);
      if (request.method === "initialize") {
        queueMicrotask(() => {
          process.stdout.write(
            `${JSON.stringify({ jsonrpc: "2.0", id: request.id, result: {} })}\n`
          );
        });
      } else if (request.method === "tools/call" && options.toolMessages?.length) {
        const message = options.toolMessages.shift();
        queueMicrotask(() => {
          process.stdout.write(
            `${JSON.stringify({ jsonrpc: "2.0", id: request.id, ...message })}\n`
          );
        });
      } else if (request.method === "tools/call" && options.toolResults?.length) {
        const result = options.toolResults.shift();
        queueMicrotask(() => {
          process.stdout.write(`${JSON.stringify({ jsonrpc: "2.0", id: request.id, result })}\n`);
        });
      }
    }
  });
  const originalEnd = process.stdin.end.bind(process.stdin);
  const end = vi.fn(() => {
    originalEnd();
    if (options.exitOnEnd) {
      queueMicrotask(() => exit(0));
    }
  });
  process.stdin.end = end;
  const kill = vi.fn(() => {
    const result = options.killResult ?? true;
    if (result && options.emitExitOnKill !== false) {
      queueMicrotask(() => exit(1));
    }
    return result;
  });
  process.kill = kill;
  return { process, end, kill, exit };
}
